const payload = ($input.first().json.payload ?? $input.first().json);
if (!payload.action) return [{ json: { status: 'error', result: {}, error: 'action is required' } }];
if (Array.isArray(payload.recipient)) return [{ json: { status: 'error', result: {}, error: 'bulk messaging is blocked by default' } }];
if (payload.channel && payload.channel !== 'whatsapp') return [{ json: { status: 'error', result: {}, error: 'only whatsapp is supported in this V1' } }];
if (payload.action === 'send_message') return [{ json: { status: 'pending_approval', result: { channel: 'whatsapp', recipient: payload.recipient, message: payload.message }, approval_required: true } }];
return [{ json: { status: 'success', result: { action: payload.action, channel: 'whatsapp', message: payload.message ?? '' }, approval_required: false } }];
